const input = $input.first().json.body || $input.first().json;
const topic = input.topic || 'Automation Best Practices';
const title = `The Complete Guide to ${topic}`;
const blog = `# ${title}\n\n## Introduction\n${topic} is transforming how teams work. This guide covers key strategies and implementation tips.\n\n## Key Points\n1. Start with clear goals\n2. Automate repetitive tasks\n3. Measure and iterate\n\n## Conclusion\nMastering ${topic} can significantly boost productivity.`;

return [{
  json: {
    topic,
    title,
    blog,
    wordCount: blog.split(/\s+/).length,
    generatedAt: new Date().toISOString()
  }
}];

const data = $input.first().json;
const titleLen = data.title.length;
const hasH1 = data.blog.startsWith('#');
const wordCount = data.wordCount;
const seoScore = Math.min(100, (titleLen >= 30 && titleLen <= 60 ? 30 : 15) + (hasH1 ? 25 : 0) + (wordCount >= 300 ? 45 : 20));

return [{
  json: {
    ...data,
    seo: {
      score: seoScore,
      passed: seoScore >= 60,
      checks: {
        titleLength: titleLen >= 30 && titleLen <= 60,
        hasHeadings: hasH1,
        wordCountOk: wordCount >= 200
      }
    }
  }
}];

const data = $input.first().json;
const autoApprove = data.seo?.passed === true;
return [{
  json: {
    ...data,
    approved: autoApprove,
    approvedBy: autoApprove ? 'auto' : 'pending-review',
    approvedAt: autoApprove ? new Date().toISOString() : null
  }
}];

const data = $input.first().json;
if (!data.approved) {
  return [{ json: { ...data, published: false, publishUrl: null, message: 'Awaiting manual approval' } }];
}
const slug = data.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/(^-|-$)/g, '');
return [{
  json: {
    ...data,
    published: true,
    publishUrl: `https://blog.example.com/${slug}`,
    publishedAt: new Date().toISOString()
  }
}];
